```python
import urllib.parse

def urllib_domain(url): 
    return '.'.join(urllib.parse.urlparse(url).netloc.split('.')[-2:])

cases = []
tmpl = "https://%s.%s"
library = "abcdefghijklmnopqrstuvwxyz0123456789-"
endings = ['com', 'io', 'net', 'gov', 'test']

def build_case():
    ending = random.choice(endings)
    use_www = random.randint(0, 9) == 0
    parts = []
    if use_www:
        parts.append('www')
    domain = "".join(random.choice(library) for _ in range(random.randint(4, 15))) 
    subdomains = [
        "".join(random.choice(library) for _ in range(random.randint(4, 15)))
        for _ in range(random.randint(1, 3))
    ]
    parts.extend(subdomains)
    parts.append(domain)
    return tmpl % (".".join(parts), ending)

for _ in range(1000000):
    cases.append(build_case())

def test(fn):
    global cases
    case = random.choice(cases)
    fn(case)
```

